{
  "name": "Kampala Prime Estates",
  "description": "A premier real estate and construction management platform based in Kampala, featuring property listings and AI-assisted support."
}

export enum PropertyType {
  HOUSE = 'House',
  LAND = 'Land',
  COMMERCIAL = 'Commercial'
}

export enum ListingStatus {
  FOR_SALE = 'For Sale',
  SOLD = 'Sold',
  PENDING = 'Pending'
}

export interface Property {
  id: string;
  title: string;
  price: number; // In UGX
  location: string;
  type: PropertyType;
  status: ListingStatus;
  bedrooms?: number;
  bathrooms?: number;
  area: string; // e.g., "50 decimals" or "400 sqm"
  description: string;
  imageUrl: string;
  features: string[];
}

export interface Service {
  id: string;
  title: string;
  description: string;
  iconName: string;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
  isError?: boolean;
}

import { GoogleGenAI, Chat, GenerateContentResponse } from "@google/genai";

let chatSession: Chat | null = null;

const SYSTEM_INSTRUCTION = `
You are "Kiboko", a friendly and professional AI Real Estate Assistant for "Kampala Prime Estates".
Your goal is to assist website visitors with inquiries about buying houses, land, surveying services, and construction management in Uganda.

Key Knowledge:
- We operate primarily in Kampala and Wakiso districts.
- We sell houses and land.
- We offer professional land surveying (boundary opening, topographic surveys).
- We offer construction project management.
- Currency is usually Ugandan Shillings (UGX). 1 USD is approx 3700-3800 UGX.

Guidelines:
- Be polite, professional, and helpful.
- If asked about specific prices not listed in the chat context, give general market ranges for Kampala (e.g., "Prime land in Naguru can range from X to Y...").
- Encouraging users to book a site visit or contact our sales team for specifics.
- Keep responses concise (under 100 words unless detailed explanation is needed).
- Use local context where appropriate (e.g., mentioning specific popular neighborhoods like Kololo, Muyenga, Kira).
`;

export const initializeChat = async (): Promise<void> => {
  if (!process.env.API_KEY) {
    console.warn("API Key not found. Chat functionality will be limited.");
    return;
  }

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    chatSession = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      },
    });
  } catch (error) {
    console.error("Failed to initialize Gemini chat:", error);
  }
};

export const sendMessageToGemini = async (message: string): Promise<string> => {
  if (!chatSession) {
    // Attempt to re-init if not available
    await initializeChat();
    if (!chatSession) {
      return "I'm currently having trouble connecting to the network. Please call us directly for assistance.";
    }
  }

  try {
    const response: GenerateContentResponse = await chatSession.sendMessage({ message });
    return response.text || "I understood that, but I couldn't generate a proper response.";
  } catch (error) {
    console.error("Error sending message to Gemini:", error);
    return "I apologize, but I encountered an error processing your request. Please try again later.";
  }
};

