import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import Footer from './components/Footer';
import GeminiAssistant from './components/GeminiAssistant';
import Home from './pages/Home';
import Listings from './pages/Listings';
import ServicesPage from './pages/ServicesPage';
import ContactPage from './pages/ContactPage';
import PropertyModal from './components/PropertyModal';
import { Property } from './types';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState('home');
  const [selectedProperty, setSelectedProperty] = useState<Property | null>(null);

  // Simple router simulation for SPA without heavy router libs
  const renderPage = () => {
    switch (currentPage) {
      case 'home':
        return <Home onNavigate={setCurrentPage} onSelectProperty={setSelectedProperty} />;
      case 'listings':
        return <Listings onSelectProperty={setSelectedProperty} />;
      case 'services':
        return <ServicesPage onContactClick={() => setCurrentPage('contact')} />;
      case 'contact':
        return <ContactPage />;
      default:
        return <Home onNavigate={setCurrentPage} onSelectProperty={setSelectedProperty} />;
    }
  };

  useEffect(() => {
    window.scrollTo(0, 0);
  }, [currentPage]);

  // Lock body scroll when modal is open
  useEffect(() => {
    if (selectedProperty) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
    return () => {
      document.body.style.overflow = 'unset';
    }
  }, [selectedProperty]);

  return (
    <div className="min-h-screen bg-white text-gray-900 font-sans selection:bg-brand-100 selection:text-brand-900">
      <Navbar currentPage={currentPage} onNavigate={setCurrentPage} />
      <main className="flex-grow">
        {renderPage()}
      </main>

      {selectedProperty && (
        <PropertyModal 
          property={selectedProperty} 
          onClose={() => setSelectedProperty(null)} 
          onContact={() => {
            setSelectedProperty(null);
            setCurrentPage('contact');
          }}
        />
      )}

      <GeminiAssistant />
      <Footer />
    </div>
  );
};

export default App;

