import { GoogleGenAI, Chat, GenerateContentResponse } from "@google/genai";

let chatSession: Chat | null = null;

const SYSTEM_INSTRUCTION = `
You are "Kiboko", a friendly and professional AI Real Estate Assistant for "Sarah's Sanctuary Homes".
Your goal is to assist website visitors with inquiries about buying houses, land, surveying services, and construction management in Uganda.

Key Knowledge:
- We operate primarily in Kampala and Wakiso districts.
- We sell houses and land.
- We offer professional land surveying (boundary opening, topographic surveys).
- We offer construction project management.
- Currency is usually Ugandan Shillings (UGX). 1 USD is approx 3700-3800 UGX.

Guidelines:
- Be polite, professional, and helpful.
- If asked about specific prices not listed in the chat context, give general market ranges for Kampala (e.g., "Prime land in Naguru can range from X to Y...").
- Encouraging users to book a site visit or contact our sales team for specifics.
- Keep responses concise (under 100 words unless detailed explanation is needed).
- Use local context where appropriate (e.g., mentioning specific popular neighborhoods like Kololo, Muyenga, Kira).
`;

export const initializeChat = async (): Promise<void> => {
  if (!process.env.API_KEY) {
    console.warn("API Key not found. Chat functionality will be limited.");
    return;
  }

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    chatSession = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      },
    });
  } catch (error) {
    console.error("Failed to initialize Gemini chat:", error);
  }
};

export const sendMessageToGemini = async (message: string): Promise<string> => {
  if (!chatSession) {
    // Attempt to re-init if not available
    await initializeChat();
    if (!chatSession) {
      return "I'm currently having trouble connecting to the network. Please call us directly for assistance.";
    }
  }

  try {
    const response: GenerateContentResponse = await chatSession.sendMessage({ message });
    return response.text || "I understood that, but I couldn't generate a proper response.";
  } catch (error) {
    console.error("Error sending message to Gemini:", error);
    return "I apologize, but I encountered an error processing your request. Please try again later.";
  }
};

import React, { useEffect, useState, useCallback } from 'react';
import { X, ChevronLeft, ChevronRight } from 'lucide-react';

interface LightboxProps {
  images: string[];
  isOpen: boolean;
  startIndex: number;
  onClose: () => void;
}

const Lightbox: React.FC<LightboxProps> = ({ images, isOpen, startIndex, onClose }) => {
  const [currentIndex, setCurrentIndex] = useState(startIndex);

  useEffect(() => {
    setCurrentIndex(startIndex);
  }, [startIndex]);

  const handleNext = useCallback(() => {
    setCurrentIndex((prev) => (prev + 1) % images.length);
  }, [images.length]);

  const handlePrev = useCallback(() => {
    setCurrentIndex((prev) => (prev - 1 + images.length) % images.length);
  }, [images.length]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (!isOpen) return;
      if (e.key === 'Escape') onClose();
      if (e.key === 'ArrowLeft') handlePrev();
      if (e.key === 'ArrowRight') handleNext();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isOpen, handleNext, handlePrev, onClose]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[70] bg-black/95 flex items-center justify-center backdrop-blur-sm animate-in fade-in duration-200">
      <button 
        onClick={onClose}
        className="absolute top-4 right-4 text-white/70 hover:text-white p-2 transition-colors z-50 rounded-full hover:bg-white/10"
        aria-label="Close lightbox"
      >
        <X className="h-8 w-8" />
      </button>

      <button 
        onClick={(e) => { e.stopPropagation(); handlePrev(); }}
        className="absolute left-4 text-white/70 hover:text-white p-2 transition-colors z-50 hover:bg-white/10 rounded-full"
        aria-label="Previous image"
      >
        <ChevronLeft className="h-10 w-10" />
      </button>

      <div className="relative w-full h-full flex items-center justify-center p-4" onClick={onClose}>
        <img 
          src={images[currentIndex]} 
          alt={`Gallery image ${currentIndex + 1}`} 
          className="max-w-full max-h-full object-contain select-none shadow-2xl"
          onClick={(e) => e.stopPropagation()}
        />
        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 text-white/90 text-sm font-medium bg-black/60 px-4 py-1.5 rounded-full backdrop-blur-md">
            {currentIndex + 1} / {images.length}
        </div>
      </div>

      <button 
        onClick={(e) => { e.stopPropagation(); handleNext(); }}
        className="absolute right-4 text-white/70 hover:text-white p-2 transition-colors z-50 hover:bg-white/10 rounded-full"
        aria-label="Next image"
      >
        <ChevronRight className="h-10 w-10" />
      </button>
    </div>
  );
};

export default Lightbox;

