export const initializeChat = async (): Promise<void> => {
  try {
    const ai = new GoogleGenAI({ apiKey: API_KEY });
    chatSession = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      },
    });
  } catch (error) {
    console.error("Failed to initialize Gemini chat:", error);
  }
};

export const sendMessageToGemini = async (message: string): Promise<string> => {
  if (!chatSession) {
    // Attempt to re-init if not available
    await initializeChat();
    if (!chatSession) {
      return "I'm currently having trouble connecting to the network. Please call us directly on 0709773348 or 0791017140.";
    }
  }

  try {
    const response: GenerateContentResponse = await chatSession.sendMessage({ message });
    return response.text || "I understood that, but I couldn't generate a proper response.";
  } catch (error) {
    console.error("Error sending message to Gemini:", error);
    // Try to re-initialize once on error
    try {
        await initializeChat();
        if (chatSession) {
            const retryResponse = await chatSession.sendMessage({ message });
            return retryResponse.text || "Please contact us on WhatsApp: 0709773348.";
        }
    } catch (retryError) {
        console.error("Retry failed:", retryError);
    }
    return "I apologize, but I encountered an error. Please contact us on WhatsApp: 0709773348.";
