import React, { useState, useRef, useEffect } from 'react';
import { MessageSquare, X, Send, Loader2, Bot, Sparkles, Trash2 } from 'lucide-react';
import { ChatMessage } from '../types';
import { sendMessageToGemini, initializeChat } from '../services/geminiService';

const GeminiAssistant: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const [isInitialized, setIsInitialized] = useState(false);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  // Initialize and Load History
  useEffect(() => {
    const init = async () => {
      const saved = localStorage.getItem('sarah_chat_history');
      let initialMessages: ChatMessage[] = [];

      if (saved) {
        try {
          const parsed = JSON.parse(saved);
          initialMessages = parsed.map((m: any) => ({
            ...m,
            timestamp: new Date(m.timestamp)
          }));
        } catch (e) {
          console.error("Failed to parse chat history", e);
        }
      }

      if (initialMessages.length === 0) {
        initialMessages = [{
          id: 'welcome',
          role: 'model',
          text: "Hello! I'm Kiboko, your virtual real estate assistant. How can I help you with properties or construction in Kampala today?",
          timestamp: new Date()
        }];
      }

      setMessages(initialMessages);

      // Convert to Gemini History Format
      const historyForGemini = initialMessages
        .filter(m => m.id !== 'welcome') // Exclude the welcome message from context usually
        .map(m => ({
          role: m.role,
          parts: [{ text: m.text }]
        }));

      await initializeChat(historyForGemini);
      setIsInitialized(true);
    };

    init();
  }, []);

  // Save to LocalStorage
  useEffect(() => {
    if (isInitialized && messages.length > 0) {
      localStorage.setItem('sarah_chat_history', JSON.stringify(messages));
    }
  }, [messages, isInitialized]);

  useEffect(() => {
    if (isOpen) {
      setTimeout(scrollToBottom, 100);
    }
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const responseText = await sendMessageToGemini(userMsg.text);
      const modelMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: new Date()
      };
      setMessages(prev => [...prev, modelMsg]);
    } catch (error) {
      console.error("Chat error", error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleClearChat = async () => {
    localStorage.removeItem('sarah_chat_history');
