      id: 'welcome',
      role: 'model',
      text: "Hello! I'm Kiboko, your virtual real estate assistant. How can I help you with properties or construction in Kampala today?",
      timestamp: new Date()
    };
    setMessages([welcomeMsg]);
    await initializeChat([]); // Reset Gemini session
