        <div className="bg-white rounded-2xl shadow-2xl w-[90vw] sm:w-96 mb-4 flex flex-col h-[500px] max-h-[70vh] border border-gray-200 animate-in fade-in slide-in-from-bottom-10 duration-300 overflow-hidden">
